{
  "title": "अप्रत्यक्ष लाइफ़टाइम्स",
  "group": "लाइफ़टाइम एलिशन",
  "options": [
    {
      "text": "सफलतापूर्वक संकलित होता है"
    },
    {
      "text": "त्रुटि: लाइफ़टाइम निर्दिष्टकर्ता गायब है",
      "hint": "लाइफ़टाइम एलिशन नियमों को याद रखें - वे मदद के लिए हैं!"
    },
    {
      "text": "त्रुटि: स्पष्ट लाइफ़टाइम आवश्यक है",
      "hint": "कम्पाइलर इसे स्वचालित रूप से समझ सकता है"
    },
    {
      "text": "त्रुटि: लाइफ़टाइम असंगतता",
      "hint": "यहाँ लाइफ़टाइम पूरी तरह मेल खाते हैं"
    }
  ],
  "questionProse": [
    "क्या यह कोड संकलित होगा? यदि हाँ, क्यों? यदि नहीं, क्या गलत है?"
  ],
  "explanationProse": [
    "यह कोड Rust के लाइफ़टाइम एलिशन नियमों के धन्यवाद से सफलतापूर्वक संकलित होता है।\n      ये नियम कंपाइलर को सामान्य पैटर्न में लाइफ़टाइम स्वचालित रूप से अनुमानित करने देते हैं।\n\n      तीन लाइफ़टाइम एलिशन नियम हैं:\n      1. प्रत्येक पैरामीटर को अपना लाइफ़टाइम पैरामीटर मिलता है\n      2. यदि ठीक एक इनपुट लाइफ़टाइम पैरामीटर है, तो वह लाइफ़टाइम सभी आउटपुट लाइफ़टाइम पैरामीटरों को सौंपा जाता है\n      3. यदि कई इनपुट लाइफ़टाइम पैरामीटर हैं, लेकिन उनमें से एक &self या &mut self है, तो self का लाइफ़टाइम सभी आउटपुट लाइफ़टाइम पैरामीटरों को सौंपा जाता है\n\n      यह फ़ंक्शन इसके बराबर है:",
    "एलिशन जहाँ काम करता है, ऐसे सामान्य पैटर्न:",
    "सर्वोत्तम अभ्यास: जब संभव हो तो एलिशन को आपके लिए काम करने दें, लेकिन समझें कब स्पष्ट लाइफ़टाइम की आवश्यकता होती है।"
  ]
}
